#include &lt;iostream&gt;#include &lt;fstream&gt;#include &lt;string&gt;#include &lt;cmath&gt;#include &quot;QuadTree.h&quot;#include &quot;FileReadAndOut.h&quot;#include &quot;Gaussian.h&quot;int main() &#123;    int height, width; double key; string filename; char Choice = &#x27;Y&#x27;;                                // 定义变量    cout &lt;&lt; &quot;请输入文件路径(不包含双引号)：&quot;; cin &gt;&gt; filename;    cout &lt;&lt; &quot;文件读取中。。。。。。&quot; &lt;&lt; endl;    int*** ImageData = Read_File_Data(filename, height, width);      if (!ImageData)return -1;        // 读取文件数据    int*** ImageDataGauss = Read_File_Data(filename, height, width); if (!ImageData)return -1;        // 读取文件数据    cout &lt;&lt; &quot;均值模糊?[y/n]:\t&quot;;    cin  &gt;&gt;  Choice;    if (Choice == &#x27;Y&#x27; || Choice == &#x27;y&#x27;)&#123;        cout &lt;&lt; &quot;//----------------------------均值模糊-------------------------------//&quot; &lt;&lt; endl;        cout &lt;&lt; &quot;请输入阈值：&quot;;                   cin &gt;&gt; key;        QuadTree tree(0, 0, width, height,ImageData, height, width);                                 // 建立四叉树        tree.Divide(ImageData, height, width, key);                                                  // 四叉树分割        tree.MeanBlur(ImageData, height, width);                                                     // 均值模糊处理        Out_File_Data(filename+&quot;_MeanBlur.ppm&quot;, ImageData, height, width);                           // 输出文件数据    &#125;    cout &lt;&lt; &quot;高斯模糊?[y/n]:\t&quot;;    cin &gt;&gt; Choice;    if (Choice == &#x27;Y&#x27; || Choice == &#x27;y&#x27;) &#123;        cout &lt;&lt; &quot;//----------------------------高斯模糊-------------------------------//&quot; &lt;&lt; endl;        cout &lt;&lt; &quot;输入高斯模糊程度(大于1):&quot;;       cin &gt;&gt; key;        GaussianBlur(ImageDataGauss, height, width, key);                                            // 高斯模糊处理        Out_File_Data(filename + &quot;_GaussianBlur.ppm&quot;, ImageDataGauss, height, width);                // 输出文件数据    &#125;    cout &lt;&lt; &quot;//----------------------------处理完成-------------------------------//&quot; &lt;&lt; endl;    cout &lt;&lt; &quot;//-------------------------------------------------------------------//&quot; &lt;&lt; endl;    Delete_Data(ImageData, height, width);                                                           // 释放内存    return 0;&#125;
QuadTree.h
#pragma once#include &lt;vector&gt;#include &lt;cmath&gt;using namespace std;class QuadTree &#123;private:    int x, y, w, h;                     //四叉树的位置和大小    double ColorAverage, EColor;        //均值和方差    bool Divided;                       //是否分割    QuadTree* topLeft;    QuadTree* topRight;    QuadTree* bottomLeft;    QuadTree* bottomRight;public:    QuadTree(int x, int y, int w, int h, int*** ImageData, int Width, int Height) :        x(x), y(y), w(w), h(h), ColorAverage(0), EColor(0), Divided(false), topLeft(nullptr), topRight(nullptr), bottomLeft(nullptr), bottomRight(nullptr)    &#123;        int l = w * h;        vector&lt;double&gt; colord(l);        double sum = 0.0;        for (int i = y; i &lt; (y + h); i++) &#123;            for (int j = x; j &lt; (x + w); j++) &#123;                colord[(i - y) * w + (j - x)] = sqrt((pow(ImageData[i][j][0], 2) + pow(ImageData[i][j][1], 2) + pow(ImageData[i][j][2], 2)) / 3);                sum += colord[(i - y) * w + (j - x)];            &#125;        &#125;        ColorAverage = sum / l;        for (int i = 0; i &lt; l; i++) EColor += pow(colord[i] - ColorAverage, 2);        EColor = sqrt(EColor / l);    &#125;    ~QuadTree() &#123;        delete topLeft;        delete topRight;        delete bottomLeft;        delete bottomRight;    &#125;    void Divide(int*** ImageData, int Width, int Height, double key) &#123;        if ((w == 1 &amp;&amp; h == 1) || (EColor &lt;= key)) return;        Divided = true;        int newW = w / 2;        int newH = h / 2;        topLeft = new QuadTree(x, y, newW, newH, ImageData, Width, Height);        topRight = new QuadTree(x + newW, y, newW, newH, ImageData, Width, Height);        bottomLeft = new QuadTree(x, y + newH, newW, newH, ImageData, Width, Height);        bottomRight = new QuadTree(x + newW, y + newH, newW, newH, ImageData, Width, Height);        topLeft-&gt;Divide(ImageData, Width, Height, key);        topRight-&gt;Divide(ImageData, Width, Height, key);        bottomLeft-&gt;Divide(ImageData, Width, Height, key);        bottomRight-&gt;Divide(ImageData, Width, Height, key);    &#125;    void MeanBlur(int*** ImageData, int Width, int Height) &#123;        if (Divided) &#123;            topLeft-&gt;MeanBlur(ImageData, Width, Height);            topRight-&gt;MeanBlur(ImageData, Width, Height);            bottomLeft-&gt;MeanBlur(ImageData, Width, Height);            bottomRight-&gt;MeanBlur(ImageData, Width, Height);        &#125;        else &#123;            int l = w * h;            int* RGB = new int[3] &#123;0, 0, 0&#125;;            for (int i = y; i &lt; y + h; i++) &#123;                for (int j = x; j &lt; x + w; j++) &#123;                    for (int k = 0; k &lt; 3; k++) &#123;                        RGB[k] += ImageData[i][j][k];                    &#125;                &#125;            &#125;            for (int k = 0; k &lt; 3; k++) RGB[k] /= l;            for (int i = y; i &lt; (y + h); i++) &#123;                for (int j = x; j &lt; (x + w); j++) &#123;                    for (int k = 0; k &lt; 3; k++) &#123;                        ImageData[i][j][k] = RGB[k];                    &#125;                &#125;            &#125;        &#125;    &#125;&#125;;
FileReadAndOut.h
#pragma once// 读取数据int*** Read_File_Data(const string filename, int&amp; Height, int&amp; Width)&#123;    ifstream readfile(filename);    if (!readfile)    &#123;        cerr &lt;&lt; &quot;Error: Unable to open file!&quot; &lt;&lt; endl;        return nullptr;    &#125;    string type;    int maxColor;    readfile &gt;&gt; type &gt;&gt; Width &gt;&gt; Height &gt;&gt; maxColor;    if (Height &lt;= 0 || Width &lt;= 0)    &#123;        cerr &lt;&lt; &quot;Error: Invalid Height or Width!&quot; &lt;&lt; endl;        return nullptr;    &#125;    //初始化数据表    int*** ImageData = new int** [Height];    for (int i = 0; i &lt; Height; i++)    &#123;        ImageData[i] = new int* [Width];        for (int j = 0; j &lt; Width; j++)            ImageData[i][j] = new int[3];    &#125;    //读数据    for (int i = 0; i &lt; Height; i++)        for (int j = 0; j &lt; Width; j++)            readfile &gt;&gt; ImageData[i][j][0] &gt;&gt; ImageData[i][j][1] &gt;&gt; ImageData[i][j][2];    readfile.close();    return ImageData;&#125;// 输出数据void Out_File_Data(const string filename, int*** ImageData, int height, int width)&#123;    ofstream outputFile(filename);    if (!outputFile)    &#123;        cerr &lt;&lt; &quot;Error: Unable to open output file!&quot; &lt;&lt; endl;        return;    &#125;    outputFile &lt;&lt; &quot;P3&quot; &lt;&lt; endl &lt;&lt; width &lt;&lt; &quot; &quot; &lt;&lt; height &lt;&lt; endl &lt;&lt; &quot;255&quot; &lt;&lt; endl;    for (int i = 0; i &lt; height; i++)    &#123;        for (int j = 0; j &lt; width; j++)            outputFile &lt;&lt; ImageData[i][j][0] &lt;&lt; &quot; &quot; &lt;&lt; ImageData[i][j][1] &lt;&lt; &quot; &quot; &lt;&lt; ImageData[i][j][2] &lt;&lt; &quot; &quot;;        outputFile &lt;&lt; endl;    &#125;    outputFile.close();&#125;//释放空间void Delete_Data(int*** ImageData, int height, int width)&#123;    for (int i = 0; i &lt; height; i++)    &#123;        for (int j = 0; j &lt; width; j++)            delete[] ImageData[i][j];        delete[] ImageData[i];    &#125;    delete[] ImageData;&#125;
Gaussian.h
#pragma once#include &lt;vector&gt;#define PI       3.14159265358979323846void GaussianBlur(int*** ImageData, int Width, int Height, int blurLevel) &#123;    if (blurLevel &lt; 1) blurLevel = 1;                                                       // 确保模糊程度至少为 1    const int kernelSize = 2 * blurLevel + 1;                                               // 内核大小为 (2 * blurLevel + 1)：1为中心，blurlevel为半径    const double sigma = static_cast&lt;double&gt;(blurLevel);                                    // 根据模糊程度设置 sigma    std::vector&lt;std::vector&lt;double&gt;&gt; kernel(kernelSize, std::vector&lt;double&gt;(kernelSize));    //创建高斯内核    double sum = 0.0;    int halfSize = kernelSize / 2;    for (int i = -halfSize; i &lt;= halfSize; i++) &#123;        for (int j = -halfSize; j &lt;= halfSize; j++) &#123;            kernel[i + halfSize][j + halfSize] = exp(-(i * i + j * j) / (2.0 * sigma * sigma)) / (2.0 * PI * sigma * sigma);            sum += kernel[i + halfSize][j + halfSize];        &#125;    &#125;    //归一    for (int i = 0; i &lt; kernelSize; i++) &#123;        for (int j = 0; j &lt; kernelSize; j++) &#123;            kernel[i][j] /= sum;        &#125;    &#125;    // 创建新的图像数据    int*** newImageData = new int** [Height];    for (int i = 0; i &lt; Height; i++) &#123;        newImageData[i] = new int* [Width];        for (int j = 0; j &lt; Width; j++) &#123;            newImageData[i][j] = new int[3];        &#125;    &#125;    // 进行模糊    for (int i = 0; i &lt; Height; i++)        for (int j = 0; j &lt; Width; j++)            for (int k = 0; k &lt; 3; k++)&#123;                double blurredPixel = 0.0;                for (int x = -halfSize; x &lt;= halfSize; x++) &#123;                    for (int y = -halfSize; y &lt;= halfSize; y++) &#123;                        int neighborX = j + x;                        int neighborY = i + y;                        if (neighborX &gt;= 0 &amp;&amp; neighborX &lt; Width &amp;&amp; neighborY &gt;= 0 &amp;&amp; neighborY &lt; Height) &#123;                            blurredPixel += ImageData[neighborY][neighborX][k] * kernel[x + halfSize][y + halfSize];                        &#125;                    &#125;                &#125;                newImageData[i][j][k] = (int)(blurredPixel);            &#125;    for (int i = 0; i &lt; Height; i++) &#123;        for (int j = 0; j &lt; Width; j++) &#123;            for (int k = 0; k &lt; 3; k++) &#123;                ImageData[i][j][k] = newImageData[i][j][k];            &#125;        &#125;    &#125;    for (int i = 0; i &lt; Height; i++) &#123;        for (int j = 0; j &lt; Width; j++)            delete[] newImageData[i][j];        delete[] newImageData[i];    &#125;    delete[] newImageData;&#125;
